Here's how to implement all three in your `EditProductPage`:

**1 & 2. Intercept back navigation and confirm:**

Override `OnBackButtonPressed` (hardware/gesture back) and hook into Shell's `Navigating` event for the shell back button:

```csharp
public partial class EditProductPage : ContentPage
{
    private bool _hasUnsavedChanges;

    protected override void OnAppearing()
    {
        base.OnAppearing();
        Shell.Current.Navigating += OnShellNavigating;
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        Shell.Current.Navigating -= OnShellNavigating;
    }

    // Intercepts Shell back button / URI navigation
    private async void OnShellNavigating(object sender, ShellNavigatingEventArgs e)
    {
        if (!_hasUnsavedChanges || e.Source != ShellNavigationSource.Pop)
            return;

        var deferral = e.GetDeferral();

        bool leave = await DisplayAlert(
            "Unsaved Changes",
            "You have unsaved changes. Discard and leave?",
            "Discard", "Stay");

        if (!leave)
            e.Cancel();

        deferral.Complete();
    }

    // Intercepts Android hardware/gesture back button
    protected override bool OnBackButtonPressed()
    {
        if (!_hasUnsavedChanges)
            return base.OnBackButtonPressed();

        MainThread.BeginInvokeOnMainThread(async () =>
        {
            bool leave = await DisplayAlert(
                "Unsaved Changes",
                "You have unsaved changes. Discard and leave?",
                "Discard", "Stay");

            if (leave)
            {
                _hasUnsavedChanges = false;
                await Shell.Current.GoToAsync("..");
            }
        });

        return true; // true = cancel default behavior
    }
}
```

**3. Custom "Cancel" back button:**

In your XAML, hide the default back button and add your own toolbar item:

```xml
<ContentPage
    xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
    xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
    x:Class="MyApp.EditProductPage"
    Shell.BackButtonBehavior="{BackButtonBehavior IsVisible=False}">

    <Shell.TitleView>
        <HorizontalStackLayout Spacing="8" VerticalOptions="Center">
            <Button Text="Cancel" 
                    BackgroundColor="Transparent"
                    TextColor="{AppThemeBinding Light=Blue, Dark=White}"
                    Clicked="OnCancelClicked" />
            <Label Text="Edit Product" 
                   VerticalOptions="Center"
                   FontAttributes="Bold" FontSize="18" />
        </HorizontalStackLayout>
    </Shell.TitleView>

    <!-- page content -->
</ContentPage>
```

```csharp
private async void OnCancelClicked(object sender, EventArgs e)
{
    if (_hasUnsavedChanges)
    {
        bool leave = await DisplayAlert(
            "Unsaved Changes",
            "You have unsaved changes. Discard and leave?",
            "Discard", "Stay");

        if (!leave) return;
    }

    _hasUnsavedChanges = false;
    await Shell.Current.GoToAsync("..");
}
```

**Key points:**
- **`e.GetDeferral()`** is required in `OnShellNavigating` to pause navigation while the async dialog is shown.
- **`OnBackButtonPressed`** handles Android's back gesture/button (not triggered on iOS/Windows).
- Set `_hasUnsavedChanges = false` before programmatic navigation to avoid re-triggering the dialog in `OnShellNavigating`.
